# add 40 varied generated templates
_more = []
rubrics = [("Case-style Post","case_lost_leads","салон","кейс"),("Case-style Post","salon_booking","салон","кейс"),("Case-style Post","clinic_booking","клиника","кейс"),("Case-style Post","ad_budget_lost","услуги","кейс"),("Myth Buster","ai_not_replace_manager","общий бизнес","миф"),("Myth Buster","myth_ai_bot_expensive","локальный бизнес","миф"),("Checklist Post","checklist_need_bot","общий бизнес","список"),("Comparison Post","bot_vs_admin","услуги","сравнение"),("Founder POV","owner_does_not_see_losses","общий бизнес","личный взгляд"),("Direct CTA Post","audit_offer","общий бизнес","оффер"),("Mistake Post","ad_budget_lost","общий бизнес","ошибка"),("Expert Insight","crm_not_filled","общий бизнес","экспертность"),("Educational Post","simple_ai_admin_offer","общий бизнес","обучение"),("Niche Post","clinic_booking","стоматология","ниша"),("Trust Post","ai_not_replace_manager","общий бизнес","доверие"),("Money Leak Post","ad_budget_lost","общий бизнес","деньги")]
starts=["Салон может терять клиентов ещё до записи.","Клиника может платить за рекламу и не видеть, где теряются пациенты.","Сильные бизнесы автоматизируют не всё подряд.","AI-бот нужен не всем. Но если заявки идут в Direct — проверьте это.","Обычный админ и AI-администратор решают разные задачи.","Я часто вижу одну и ту же ошибку владельцев.","Пять признаков, что обработка заявок уже проседает.","Реклама приводит интерес, но не доводит его до записи.","Доверие рождается не из обещаний, а из понятного процесса.","Сегодняшний оффер простой: найти дырку в пути заявки."]
for i in range(40):
    rubric, angle, niche, form = rubrics[i % len(rubrics)]
    cta_type = list(CTA_BY_TYPE)[i % len(CTA_BY_TYPE)]
    hook = starts[i % len(starts)] + f" Ситуация #{i+1}."
    body = f"{hook}\n\nФормат: {form}. В нише {niche} заявка часто проходит через Direct, WhatsApp или Telegram, а потом вручную попадает к менеджеру. На этом участке теряются заявки, скорость, контекст и follow-up; тёплый клиент уходит без продажи.\n\nAI-администратор отвечает первым, уточняет запрос, фиксирует контакт и передаёт понятную заявку в CRM или человеку."
    _more.append((rubric, angle if i<16 else f"{angle}_{i}", ["доверие","охват","прогрев","продажа","экспертность","личка"][i%6], niche, cta_type, f"закрывает задачу: {form}", body, cta_type))

GROWTH_TEMPLATES = tuple(GrowthTemplate(r,a,g,n,c,w, f"{body}\n\n{CTA_BY_TYPE[cta]}") for r,a,g,n,c,w,body,cta in (_RAW+_more))
VIRAL_THREADS_TEMPLATES = tuple(t.text for t in GROWTH_TEMPLATES)
